package scheduler

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/scheduler"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type SchedulerProxy struct {
	scheduler.UnimplementedSchedulerServer
	client scheduler.SchedulerClient
}

func init() {
	proxyutil.Register(&scheduler.Scheduler_ServiceDesc, NewSchedulerProxy)
}
func NewSchedulerProxy(cc grpc.ClientConnInterface) scheduler.SchedulerServer {
	return &SchedulerProxy{client: scheduler.NewSchedulerClient(cc)}
}
func (p *SchedulerProxy) Schedule(ctx context.Context, in *scheduler.ScheduledActionRequest) (*scheduler.ScheduledActionResponse, error) {
	return proxyutil.ProxyMethod[scheduler.ScheduledActionRequest, scheduler.ScheduledActionResponse](p.client.Schedule)(ctx, in)
}
func (p *SchedulerProxy) Cancel(ctx context.Context, in *scheduler.CancelActionRequest) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[scheduler.CancelActionRequest, emptypb.Empty](p.client.Cancel)(ctx, in)
}
func (p *SchedulerProxy) List(ctx context.Context, in *scheduler.ListActionRequest) (*scheduler.ListActionResponse, error) {
	return proxyutil.ProxyMethod[scheduler.ListActionRequest, scheduler.ListActionResponse](p.client.List)(ctx, in)
}
